sql:
SELECT AVG(pupils_per_teacher) 
FROM teacher_to_pupil_ratio 
WHERE pupils_per_teacher > (SELECT AVG(pupils_per_teacher) FROM teacher_to_pupil_ratio);

SELECT COUNT(*) AS num_public_schools
FROM schools
WHERE type = 'public';

SELECT name, type 
FROM schools 
WHERE school_id = 1;

SELECT name 
FROM schools 
WHERE school_id = 1;

